def get_versions():

    try:
        import pkg_resources
        import platform
        import sys

        versions = {
            'python': sys.version.split()[0],
            'platform': platform.platform(),
            'pkg_resources': pkg_resources.__version__
        }

        return versions

    except Exception:
        # Return default version info if unable to get actual versions
        return {
            'python': 'unknown',
            'platform': 'unknown',
            'pkg_resources': 'unknown'
        }

