def render(pieces, style):

    if style == 'pep440':
        # PEP 440 format: N.N[.N]+[{a|b|c|rc}N][.postN][.devN]
        version = '.'.join(str(p) for p in pieces[:3])
        if len(pieces) > 3:
            if pieces[3] == 'alpha':
                version += f'a{pieces[4]}'
            elif pieces[3] == 'beta':
                version += f'b{pieces[4]}'
            elif pieces[3] == 'candidate':
