def size_to_bytes(size: str) -> int:

    units = {
        'K': 1000,
        'M': 1000000,
        'G': 1000000000,
        'T': 1000000000000,
    }

    size = size.strip().upper()

    if size[-1] in units:
        return int(float(size[:-1]) * units[size[-1]])

    return int(size)

